const data = $input.first().json;
if (data.status === 'rejected') return [{ json: data }];
const plan = data.plan;
const required = ['featureName','featureArchetype','businessIntent','repoContext','architectureImpact','automationScope','files','testingStrategy','factoryExecutionPlan','acceptanceCriteria'];
const validArchetypes = ['utility-feature','mobile-screen-feature','firestore-feature','cloud-function-feature','maps-tracking-feature','native-integration-feature','payments-stripe-connect-feature','ai-support-agent-feature','voice-agent-elevenlabs-feature','landing-react-vite-feature'];
const errors = [];
required.filter(f => !plan[f]).forEach(f => errors.push('Missing required field: ' + f));
if (!validArchetypes.includes(plan.featureArchetype)) errors.push('Invalid featureArchetype: ' + plan.featureArchetype);
if ((!plan.files || (!plan.files.create || !plan.files.create.length)) && (!plan.files || (!plan.files.modify || !plan.files.modify.length))) errors.push('files.create or files.modify must have at least one entry');
if (!plan.testingStrategy || !plan.testingStrategy.commands || !plan.testingStrategy.commands.length) errors.push('testingStrategy.commands must not be empty');
if (errors.length > 0) return [{ json: { ...data, status: 'rejected', errors } }];
return [{ json: { ...data, status: 'validated' } }];

const data = $input.first().json;
const plan = data.plan;
const archetype = plan.featureArchetype;
const risk = (plan.architectureImpact && plan.architectureImpact.riskLevel) || 'low';
const nativeRisk = plan.architectureImpact && plan.architectureImpact.nativeRisk === true;
const levelMap = {
  'utility-feature': 'L0',
  'landing-react-vite-feature': 'L0',
  'mobile-screen-feature': 'L1',
  'ai-support-agent-feature': 'L1',
  'firestore-feature': (risk === 'high' || risk === 'critical') ? 'L2' : 'L1',
  'cloud-function-feature': risk === 'critical' ? 'L2' : 'L1',
  'maps-tracking-feature': nativeRisk ? 'L2' : 'L1',
  'native-integration-feature': 'L2',
  'payments-stripe-connect-feature': 'L2',
  'voice-agent-elevenlabs-feature': 'L2'
};
const executionLevel = levelMap[archetype] || 'L2';
const model = executionLevel === 'L0' ? 'claude-haiku-4-5-20251001' : 'claude-sonnet-4-6';
const maxRetries = (plan.factoryExecutionPlan && plan.factoryExecutionPlan.maxRetries != null) ? plan.factoryExecutionPlan.maxRetries : 2;
return [{ json: { ...data, executionLevel, riskLevel: risk, model, maxRetries, status: 'classified' } }];

const cmd = $input.first().json;
const data = $('Classify Risk').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Setup sandbox failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'sandbox_ready' } }];

const cmd = $input.first().json;
const data = $('After Setup Sandbox').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Clone failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'cloned' } }];

const data = $input.first().json;
const plan = data.plan;
const blocks = (plan.selectedBuildingBlocks || []).map(function(b) { return b.name || b; }).join(', ');
const contextBundle = [
  '# IMPLEMENTATION PLAN\n' + JSON.stringify(plan, null, 2),
  '# ARCHETYPE: ' + plan.featureArchetype,
  '# EXECUTION LEVEL: ' + data.executionLevel,
  '# RISK LEVEL: ' + data.riskLevel,
  '# BUILDING BLOCKS: ' + (blocks || 'none'),
  '# FILES TO CREATE:\n' + JSON.stringify((plan.files && plan.files.create) || [], null, 2),
  '# FILES TO MODIFY:\n' + JSON.stringify((plan.files && plan.files.modify) || [], null, 2),
  '# DO NOT TOUCH:\n' + JSON.stringify((plan.files && plan.files.doNotTouch) || [], null, 2),
  '# TESTING STRATEGY:\n' + JSON.stringify(plan.testingStrategy, null, 2),
  '# ACCEPTANCE CRITERIA:\n' + (plan.acceptanceCriteria || []).map(function(c) { return '- ' + c; }).join('\n')
].join('\n\n---\n\n');
return [{ json: { ...data, contextBundle, status: 'context_loaded' } }];

const data = $input.first().json;
const plan = data.plan;
const acceptanceCriteria = (plan.acceptanceCriteria || []).map(function(c) { return '- ' + c; }).join('
');
const patterns = (plan.repoContext && plan.repoContext.existingPatternsToFollow || []).join('
');
const filesToCreate = JSON.stringify((plan.files && plan.files.create) || [], null, 2);
const testingStrategy = JSON.stringify(plan.testingStrategy, null, 2);
const userContent = 'Generate Jest tests for this feature.

IMPLEMENTATION PLAN:
' + JSON.stringify(plan, null, 2) + '

FILES TO CREATE:
' + filesToCreate + '

TESTING STRATEGY:
' + testingStrategy + '

ACCEPTANCE CRITERIA:
' + acceptanceCriteria + '

EXISTING PATTERNS:
' + patterns + '

RULES:
- Pure utilities: import directly, no renderHook, no React Testing Library
- React hooks: use renderHook from @testing-library/react-native
- Tests must FAIL before implementation exists, PASS after
- No real Firebase/Stripe/OpenAI/ElevenLabs calls — use jest.mock()
- Test edge cases and error paths
- Use describe/it blocks with clear readable names

Output this JSON structure ONLY — no markdown, no code blocks, no explanation:
{"tests":[{"filePath":"src/utils/__tests__/example.test.ts","content":"import { example } from "../example";
describe(...)"}]}';
const apiRequestBody = {
  model: data.model,
  max_tokens: 8096,
  system: 'You are the LogiTruck Factory test generator. Return ONLY valid JSON — no markdown, no code blocks, no explanation.',
  messages: [{ role: 'user', content: userContent }]
};
return [{ json: { ...data, apiRequestBody } }];

const response = $input.first().json;
const data = $('Load Context Bundle').first().json;
let tests = { tests: [] };
try {
  const raw = (response.content && response.content[0] && response.content[0].text) || '{}';
  const cleaned = raw.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  tests = JSON.parse(cleaned);
  if (!Array.isArray(tests.tests)) tests = { tests: [] };
} catch(e) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Failed to parse tests response: ' + e.message] } }];
}
return [{ json: { ...data, testsData: tests, status: 'tests_generated' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const tests = (data.testsData && data.testsData.tests) || [];
const repoDir = path.resolve(data.repoDir);
const written = [];
for (const test of tests) {
  if (!test.filePath || !test.content) continue;
  const resolved = path.resolve(repoDir, test.filePath);
  if (!resolved.startsWith(repoDir + path.sep) && resolved !== repoDir) {
    return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Path traversal blocked: ' + test.filePath] } }];
  }
  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, test.content, 'utf8');
  written.push(test.filePath);
}
return [{ json: { ...data, testsWritten: written, status: 'tests_written' } }];

const data = $input.first().json;
const plan = data.plan;
const filesToCreate = JSON.stringify((plan.files && plan.files.create) || [], null, 2);
const filesToModify = JSON.stringify((plan.files && plan.files.modify) || [], null, 2);
const doNotTouch = JSON.stringify((plan.files && plan.files.doNotTouch) || [], null, 2);
const patterns = (plan.repoContext && plan.repoContext.existingPatternsToFollow || []).join('
');
const antiPatterns = (plan.repoContext && plan.repoContext.knownAntiPatternsToAvoid || []).join('
');
const tests = JSON.stringify(data.testsData, null, 2);
const userContent = 'Generate implementation files for this feature.

IMPLEMENTATION PLAN:
' + JSON.stringify(plan, null, 2) + '

GENERATED TESTS — make these pass:
' + tests + '

FILES TO CREATE:
' + filesToCreate + '

FILES TO MODIFY:
' + filesToModify + '

DO NOT TOUCH:
' + doNotTouch + '

EXISTING PATTERNS TO FOLLOW:
' + patterns + '

ANTI-PATTERNS TO AVOID:
' + antiPatterns + '

RULES:
- Reuse existing patterns from repoContext
- Avoid new dependencies unless the plan explicitly allows them
- Pure functions must be deterministic and side-effect free
- Use explicit TypeScript types and explicit return types
- No any types
- No hidden Firebase/network/native calls in utilities
- This is a sandbox integration candidate only

Output this JSON structure ONLY — no markdown, no code blocks:
{"files":[{"filePath":"src/utils/example.ts","content":"export ..."}]}';
const apiRequestBody = {
  model: data.model,
  max_tokens: 8096,
  system: 'You are the LogiTruck Factory implementation generator. Return ONLY valid JSON — no markdown, no code blocks, no explanation.',
  messages: [{ role: 'user', content: userContent }]
};
return [{ json: { ...data, apiRequestBody } }];

const response = $input.first().json;
const data = $('Write Tests').first().json;
let impl = { files: [] };
try {
  const raw = (response.content && response.content[0] && response.content[0].text) || '{}';
  const cleaned = raw.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  impl = JSON.parse(cleaned);
  if (!Array.isArray(impl.files)) impl = { files: [] };
} catch(e) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Failed to parse implementation: ' + e.message] } }];
}
return [{ json: { ...data, implData: impl, status: 'implementation_generated' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const files = (data.implData && data.implData.files) || [];
const doNotTouch = (data.plan.files && data.plan.files.doNotTouch) || [];
const repoDir = path.resolve(data.repoDir);
const written = [];
for (const file of files) {
  if (!file.filePath || !file.content) continue;
  if (doNotTouch.some(function(p) { return file.filePath.includes(p); })) {
    return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Attempted to write protected file: ' + file.filePath] } }];
  }
  const resolved = path.resolve(repoDir, file.filePath);
  if (!resolved.startsWith(repoDir + path.sep) && resolved !== repoDir) {
    return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Path traversal blocked: ' + file.filePath] } }];
  }
  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, file.content, 'utf8');
  written.push(file.filePath);
}
return [{ json: { ...data, filesWritten: written, status: 'files_written' } }];

const cmd = $input.first().json;
const data = $('Write Files').first().json;
const passed = cmd.exitCode === 0;
const output = 'VALIDATION ATTEMPT 1
EXIT_CODE: ' + cmd.exitCode + '

STDOUT:
' + cmd.stdout + '

STDERR:
' + cmd.stderr;
return [{ json: { ...data, validationOutput: output, validationPassed: passed, status: passed ? 'validation_passed' : 'validation_failed' } }];

const response = $input.first().json;
const data = $('Parse Validation Result').first().json;
let analysis = { retryAllowed: false, failureType: 'unknown', rootCause: 'Could not parse analysis', patchInstructions: '' };
try {
  const raw = (response.content && response.content[0] && response.content[0].text) || '{}';
  const cleaned = raw.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis.rootCause = 'Parse error: ' + e.message;
}
const retryAllowed = analysis.retryAllowed === true && data.retryCount < data.maxRetries;
return [{ json: { ...data, failureAnalysis: analysis, retryAllowed, status: 'failure_analyzed' } }];

const response = $input.first().json;
const data = $('Parse Failure Analysis').first().json;
let patch = { patches: [], reason: 'No patches generated' };
try {
  const raw = (response.content && response.content[0] && response.content[0].text) || '{}';
  const cleaned = raw.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  patch = JSON.parse(cleaned);
  if (!Array.isArray(patch.patches)) patch = { patches: [], reason: 'Invalid patch format' };
} catch(e) {
  patch = { patches: [], reason: 'Parse error: ' + e.message };
}
return [{ json: { ...data, patchData: patch, status: 'patch_generated' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const patches = (data.patchData && data.patchData.patches) || [];
const doNotTouch = (data.plan.files && data.plan.files.doNotTouch) || [];
const repoDir = path.resolve(data.repoDir);
const patchedFiles = [];
for (const patch of patches) {
  if (!patch.filePath || !patch.content) continue;
  if (doNotTouch.some(function(p) { return patch.filePath.includes(p); })) continue;
  const resolved = path.resolve(repoDir, patch.filePath);
  if (!resolved.startsWith(repoDir + path.sep) && resolved !== repoDir) continue;
  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, patch.content, 'utf8');
  patchedFiles.push(patch.filePath);
}
const retryEntry = {
  attempt: data.retryCount + 1,
  failureType: data.failureAnalysis && data.failureAnalysis.failureType,
  rootCause: data.failureAnalysis && data.failureAnalysis.rootCause,
  patchedFiles,
  reason: data.patchData && data.patchData.reason
};
return [{ json: { ...data, retryCount: data.retryCount + 1, retryHistory: [...data.retryHistory, retryEntry], status: 'patch_applied' } }];

const cmd = $input.first().json;
const data = $('Apply Patch').first().json;
const passed = cmd.exitCode === 0;
const output = 'VALIDATION ATTEMPT ' + data.retryCount + '
EXIT_CODE: ' + cmd.exitCode + '

STDOUT:
' + cmd.stdout + '

STDERR:
' + cmd.stderr;
return [{ json: { ...data, validationOutput: output, validationPassed: passed, status: passed ? 'retry_passed' : 'retry_failed' } }];

const fs = require('fs');
const data = $input.first().json;
const h = data.handoffPath;
fs.mkdirSync(h + '/generated-files', { recursive: true });
fs.mkdirSync(h + '/tests', { recursive: true });

fs.writeFileSync(h + '/IMPLEMENTATION_PLAN.json', JSON.stringify(data.plan, null, 2), 'utf8');
fs.writeFileSync(h + '/validation-output.txt', data.validationOutput || 'No validation output.', 'utf8');

const retrySummary = data.retryHistory && data.retryHistory.length
  ? '# Retry Summary\n\nTotal Retries: ' + data.retryCount + '\n\n' + data.retryHistory.map(function(r, i) {
      return '## Attempt ' + (i+1) + '\n- Failure Type: ' + r.failureType + '\n- Root Cause: ' + r.rootCause + '\n- Patched: ' + ((r.patchedFiles || []).join(', ') || 'none') + '\n- Reason: ' + r.reason;
    }).join('\n\n')
  : '# Retry Summary\n\nNo retries performed.';
fs.writeFileSync(h + '/retry-summary.md', retrySummary, 'utf8');

const riskNotes = '# Risk Notes\n\n- Feature: ' + data.featureName + '\n- Archetype: ' + data.featureArchetype + '\n- Execution Level: ' + data.executionLevel + '\n- Risk Level: ' + data.riskLevel + '\n- Validation Passed: ' + data.validationPassed + '\n- Retries: ' + data.retryCount + ' / ' + data.maxRetries + '\n\n## Errors\n' + (data.errors && data.errors.length ? data.errors.map(function(e) { return '- ' + e; }).join('\n') : 'None');
fs.writeFileSync(h + '/risk-notes.md', riskNotes, 'utf8');

const plan = data.plan;
const steps = (plan.claudeCodeIntegrationPlan && plan.claudeCodeIntegrationPlan.steps) || (plan.claudeCodeHandoff && plan.claudeCodeHandoff.tasks) || ['1. Review generated files', '2. Apply to production repo', '3. Run full test suite', '4. Validate runtime behavior', '5. Commit if all checks pass'];
const claudeSteps = '# Claude Code Integration Steps\n\n' + steps.map(function(s,i) { return (i+1) + '. ' + s; }).join('\n') + '\n\n## Files Generated (sandbox only)\n' + ((data.filesWritten || []).map(function(f) { return '- ' + f; }).join('\n') || 'None') + '\n\n## Tests Generated (sandbox only)\n' + ((data.testsWritten || []).map(function(f) { return '- ' + f; }).join('\n') || 'None') + '\n\n## Validation: ' + (data.validationPassed ? 'PASSED' : 'FAILED') + '\n\n> IMPORTANT: Factory output is a sandbox candidate only. Claude Code owns integration and production commit.';
fs.writeFileSync(h + '/claude-integration-steps.md', claudeSteps, 'utf8');

const rollbackSteps = (plan.rollbackPlan && plan.rollbackPlan.steps && plan.rollbackPlan.steps.length)
  ? plan.rollbackPlan.steps.map(function(s,i) { return (i+1) + '. ' + s; }).join('\n')
  : '1. Delete sandbox directory — no production changes were made.\n   Path: ' + data.workDir;
fs.writeFileSync(h + '/rollback-plan.md', '# Rollback Plan\n\n' + rollbackSteps, 'utf8');

let finalStatus = 'ready';
if (!data.validationPassed && data.retryCount > 0) finalStatus = 'needs_fix';
if (!data.validationPassed && data.retryAllowed === false) finalStatus = 'escalated';
if (data.status === 'failure_analyzed' && !data.retryAllowed) finalStatus = 'escalated';

const manifest = {
  featureName: data.featureName,
  featureArchetype: data.featureArchetype,
  executionLevel: data.executionLevel,
  riskLevel: data.riskLevel,
  status: finalStatus,
  filesWritten: data.filesWritten || [],
  testsWritten: data.testsWritten || [],
  validationPassed: data.validationPassed || false,
  retryCount: data.retryCount,
  handoffPath: h,
  timestamp: new Date().toISOString()
};
fs.writeFileSync(h + '/manifest.json', JSON.stringify(manifest, null, 2), 'utf8');
return [{ json: { ...data, finalStatus, manifest, status: 'handoff_packaged' } }];
